const weather = $input.first().json.weather[0].main;
const temp = $input.first().json.main.temp;
const location = $input.first().json.name;

const messages = {
  Rain: {
    crop: {
      English: "Heavy rain expected today. Cover your crops to prevent flooding and hold off on irrigation.",
      Yoruba: "Òjò ńlá ń rọ̀ lónìí. Bo àwọn ohun ọ̀gbìn rẹ láti dènà ìkún omi kí o sì dáwọ́ ìfúnpọ̀ omi dúró.",
      Igbo: "A na-atụ anya oké mmiri ozuzo taa. Kpuchie ihe ubi gị iji gbochie idei mmiri ma kwụsị ịgbara mmiri.",
      Hausa: "Ana sa ran ruwan sama mai ƙarfi a yau. A rufe amfanin gonakinku don hana ambaliya da kuma dakatar da ban ruwa."
    },
    animal: {
      English: "Heavy rain expected today. Move your animals to shelter immediately and check for waterlogging in their pen.",
      Yoruba: "Òjò líle ń rọ̀ lónìí. Ẹ kó àwọn ẹranko yín lọ síbi ààbò lẹ́sẹ̀kẹsẹ̀ kí ẹ sì ṣàyẹ̀wò bóyá omi ti wọ́ nínú àgọ́ wọn.",
      Igbo: "A na-atụ anya oké mmiri ozuzo taa. Bufee anụmanụ gị gaa ebe obibi ozugbo ma lelee ma mmiri ọ na-ezo n'ogige ha.",
      Hausa: "Ana sa ran ruwan sama mai ƙarfi a yau. Ku kwashe dabbobinku zuwa mafaka nan da nan kuma ku duba ko akwai ruwa a cikin rumfar su."
    }
  },
  Clouds: {
    crop: {
      English: "Cloudy skies today. Good conditions for light farm work. Monitor for possible rain later.",
      Yoruba: "Ojú ọ̀run tó ń ṣú mànàmáná lónìí. Ipò tó dára fún iṣẹ́ oko tó rọrùn. Máa kíyèsí bóyá òjò lè rọ̀ nígbà tó bá yá.",
      Igbo: "Eluigwe ígwé ojii taa. Ọnọdụ dị mma maka ọrụ ugbo dị mfe. Lelee maka mmiri ozuzo nwere ike izo ma emechaa.",
      Hausa: "Sama mai gajimare a yau. Yanayi mai kyau don aikin gona mai sauƙi. Kula da yiwuwar ruwan sama daga baya."
    },
    animal: {
      English: "Cloudy skies today. Good day for your animals to graze. Watch for rain later.",
      Yoruba: "Ojú ọ̀run tó ń ṣú mànàmáná lónìí. Ọjọ́ rere fún àwọn ẹranko rẹ láti jẹko. Máa ṣọ́ra fún òjò tó ń bọ̀.",
      Igbo: "Eluigwe ígwé ojii taa. Ụbọchị ọma maka anụmanụ gị ịta nri. Lelee maka mmiri ozuzo ma emechaa.",
      Hausa: "Sama mai gajimare a yau. Barka da rana dabbobinku su yi kiwo. Ku kula da ruwan sama daga baya."
    }
  },
  Clear: {
    crop: {
      English: "Sunny day today. Irrigate your crops early before the sun gets too strong.",
      Yoruba: "Oòrùn òrùn lónìí. Fi omi bomirin àwọn ohun ọ̀gbìn rẹ ní kùtùkùtù kí oòrùn tó le.",
      Igbo: "Taa, anwụ na-acha. Gbaa ihe ubi gị mmiri n'oge tupu anyanwụ apụta oke ike.",
      Hausa: "Rana mai haske a yau. Yi ban ruwa ga amfanin gona da wuri kafin rana ta yi ƙarfi sosai."
    },
    animal: {
      English: "Very sunny today. Make sure your animals have enough water and shade throughout the day.",
      Yoruba: "Oòrùn máa ń tàn gan-an lónìí. Rí i dájú pé àwọn ẹranko rẹ ní omi àti òjìji tó tó ní gbogbo ọjọ́ náà.",
      Igbo: "Anwụ na-acha nke ukwuu taa. Hụ na anụmanụ gị nwere mmiri na ndò zuru oke n'ụbọchị niile.",
      Hausa: "Rana tana da matuƙar haske a yau. Tabbatar dabbobinku suna da isasshen ruwa da inuwa a duk tsawon yini."
    }
  },
  Thunderstorm: {
    crop: {
      English: "Severe weather today. Do not go to the farm. Keep all crops covered and stay safe.",
      Yoruba: "Oju ojo lile loni. Maṣe lọ si oko. Pa gbogbo irugbin mọ ki o si wa ni ailewu.",
      Igbo: "Ihu igwe dị oke njọ taa. Agala ugbo. Kpuchie ihe ubi niile ma nọrọ na nchekwa.",
      Hausa: "Mummunan yanayi a yau. Kada ku je gona. Ku rufe dukkan amfanin gona ku zauna lafiya."
    },
    animal: {
      English: "Severe weather today. Keep all animals indoors and secure. Do not move them today.",
      Yoruba: "Oju ojo lile loni. Pa gbogbo ẹranko mọ́ sínú ilé kí o sì ní ààbò. Ma se gbe won lo loni.",
      Igbo: "Ihu igwe dị oke njọ taa. Debe anụmanụ niile n'ime ụlọ ma chekwaa ha. Ebugharịla ha taa.",
      Hausa: "Mummunan yanayi a yau. A ajiye dukkan dabbobi a cikin gida kuma a tsare su. Kada a motsa su a yau."
    }
  },
  Drizzle: {
    crop: {
      English: "Light rain today. Delay irrigation and monitor your crops for waterlogging.",
      Yoruba: "Òjò díẹ̀ lónìí. Dá ìfúnpọ̀ omi dúró kí o sì máa ṣọ́ àwọn ohun ọ̀gbìn rẹ fún ìgbóná omi.",
      Igbo: "Mmiri ozuzo taa. Kwụsị ịgba mmiri ma lelee ihe ubi gị maka oke mmiri.",
      Hausa: "Ruwan sama mai sauƙi a yau. Dakatar da ban ruwa kuma ku sa ido kan amfanin gonakinku don kada su yi ambaliya."
    },
    animal: {
      English: "Light rain today. Animals can still graze but monitor conditions closely.",
      Yoruba: "Òjò díẹ̀ lónìí. Àwọn ẹranko ṣì lè jẹko ṣùgbọ́n wọ́n ń ṣe àkíyèsí ipò wọn dáadáa.",
      Igbo: "Mmiri ozuzo dị obere taa. Anụmanụ ka nwere ike ịta nri mana ha na-enyocha ọnọdụ ha nke ọma.",
      Hausa: "Ruwan sama mai sauƙi a yau. Dabbobi har yanzu suna iya kiwo amma suna sa ido sosai kan yanayin."
    }
  }
};

const defaultMessages = {
  crop: {
    English: "Please check weather conditions today before any farming activities.",
    Yoruba: "Jọwọ ṣàyẹ̀wò ipò ojú ọjọ́ lónìí ṣáájú iṣẹ́ oko eyikeyii.",
    Igbo: "Biko lelee ọnọdụ ihu igwe taa tupu ọ bụ ọrụ ugbo ọ bụla.",
    Hausa: "Don Allah duba yanayin yau kafin kowane aiki na gona."
  },
  animal: {
    English: "Please check weather conditions today before moving your animals.",
    Yoruba: "Jọwọ ṣàyẹ̀wò ipò ojú ọjọ́ lónìí ṣáájú gbígbe àwọn ẹranko rẹ.",
    Igbo: "Biko lelee ọnọdụ ihu igwe taa tupu ibugharị anụmanụ gị.",
    Hausa: "Don Allah duba yanayin yau kafin a motsa dabbobinku."
  }
};

const weatherMessages = messages[weather] || defaultMessages;

return [{
  json: {
    weatherCondition: weather,
    temperature: temp,
    location: location,
    cropMessages: weatherMessages.crop || defaultMessages.crop,
    animalMessages: weatherMessages.animal || defaultMessages.animal
  }
}];

const weatherData = $('Weather').first().json;
const farmer = $('Get row(s) in sheet').first().json;
const farmerType = farmer['Farmer Type'];
const language = farmer['Preferred Language'];

let messages;

if (farmerType === "Crop Farmer") {
  messages = weatherData.cropMessages;
} else if (farmerType === "Animal Farmer") {
  messages = weatherData.animalMessages;
} else {
  messages = weatherData.cropMessages;
}

const message = messages[language] || messages["English"];

const greeting = {
  "English": "Hello",
  "Yoruba": "E kaaro",
  "Igbo": "Ututu oma",
  "Hausa": "Barka da safe"
};

const salutation = greeting[language] || "Hello";

return [{
  json: {
    name: farmer['Farmer Name'],
    phone: farmer['Phone Number'],
    email: farmer['Email Address'],
    language: language,
    channel: farmer['Preferred Channel'],
    message: salutation + " " + farmer['Farmer Name'] + ", " + message
  }
}];
